// ─────────────────────────────────────────────────────────────
//  Dashboard.js — Main Dashboard Page
//
//  Fetches REAL data from MongoDB via Node.js backend.
//  Uses JWT token (set in AuthContext) for all API calls.
// ─────────────────────────────────────────────────────────────

import { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import {
  AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
} from 'recharts';

export default function Dashboard() {
  const { user, logout } = useAuth();
  const navigate         = useNavigate();

  // All data from backend
  const [kpis,         setKpis]         = useState([]);
  const [revenue,      setRevenue]      = useState([]);
  const [anomalies,    setAnomalies]    = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [dataLoading,  setDataLoading]  = useState(true);

  // AI state
  const [aiQuestion,   setAiQuestion]   = useState('');
  const [aiResponse,   setAiResponse]   = useState('');
  const [aiLoading,    setAiLoading]    = useState(false);

  // Sidebar
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [activePage,  setActivePage]  = useState('Overview');

  // ── Fetch all data on mount ──────────────────────────────
  useEffect(() => {
    fetchAllData();
  }, []);

  const fetchAllData = async () => {
    setDataLoading(true);
    try {
      const [kpiRes, revRes, anomRes, txnRes] = await Promise.all([
        axios.get('/api/dashboard/kpis'),
        axios.get('/api/dashboard/revenue'),
        axios.get('/api/dashboard/anomalies'),
        axios.get('/api/transactions?limit=6'),
      ]);
      setKpis(kpiRes.data.kpis);
      setRevenue(revRes.data.revenue);
      setAnomalies(anomRes.data.anomalies);
      setTransactions(txnRes.data.transactions);
    } catch (err) {
      console.error('Data fetch error:', err);
    } finally {
      setDataLoading(false);
    }
  };

  // ── Ask Claude AI ────────────────────────────────────────
  const askAI = async (q) => {
    const question = q || aiQuestion;
    if (!question.trim()) return;
    setAiLoading(true);
    setAiResponse('');
    try {
      const res = await axios.post('/api/ai/analyze', { question });
      setAiResponse(res.data.analysis);
    } catch {
      setAiResponse('AI analysis failed. Check your Anthropic API key in backend .env');
    } finally {
      setAiLoading(false);
    }
  };

  const handleLogout = () => { logout(); navigate('/login'); };

  const segmentData = [
    { name: 'Transfers',   value: 38, color: '#2a78d6' },
    { name: 'Payments',    value: 29, color: '#1baf7a' },
    { name: 'Investments', value: 21, color: '#eda100' },
    { name: 'Withdrawals', value: 12, color: '#4a3aa7' },
  ];

  const navItems = ['Overview', 'Revenue', 'Transactions', 'Fraud Detection', 'AI Insights'];
  const quickActions = [
    { label: '📈 Revenue Forecast',  q: 'Analyze revenue trend and forecast next month.' },
    { label: '🛡️ Fraud Analysis',    q: 'Detect anomalies and fraud in my transactions.' },
    { label: '⚠️ Risk Assessment',   q: 'Assess portfolio risk and give recommendations.' },
    { label: '📉 Low Revenue Dip',   q: 'Why did revenue dip and how to prevent it?' },
  ];

  if (dataLoading) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'var(--bg)' }}>
      <div style={{ textAlign:'center' }}>
        <div style={{ width:40, height:40, border:'3px solid var(--border)', borderTopColor:'var(--accent)', borderRadius:'50%', animation:'spin 0.8s linear infinite', margin:'0 auto 14px' }} />
        <p style={{ color:'var(--text-muted)', fontSize:13 }}>Loading your financial data from MongoDB...</p>
      </div>
    </div>
  );

  return (
    <div style={{ minHeight:'100vh', background:'var(--bg)', display:'flex', flexDirection:'column' }}>

      {/* ── TOP BAR ── */}
      <header style={S.topbar}>
        <div style={S.topLeft}>
          <button style={S.menuBtn} onClick={() => setSidebarOpen(x => !x)}>☰</button>
          <div style={S.logoBox}>📈</div>
          <span style={S.brand}>FinSight AI</span>
          <span style={S.badge}>LIVE · MongoDB</span>
        </div>
        <div style={S.topRight}>
          <div style={S.userChip}>
            {user?.photo
              ? <img src={user.photo} alt="" style={{ width:24, height:24, borderRadius:'50%' }} />
              : <div style={S.avatarSmall}>{user?.name?.[0]}</div>
            }
            <span style={{ fontSize:13, color:'var(--text-secondary)' }}>{user?.name}</span>
            <span style={{ fontSize:10, color:'var(--text-muted)' }}>·</span>
            <span style={{ fontSize:10, color:'var(--green)', textTransform:'uppercase', fontWeight:700 }}>{user?.role}</span>
          </div>
          <button style={S.logoutBtn} onClick={handleLogout}>Sign Out</button>
        </div>
      </header>

      <div style={{ display:'flex', flex:1 }}>

        {/* ── SIDEBAR ── */}
        {sidebarOpen && (
          <aside style={S.sidebar}>
            <div style={S.sideLabel}>NAVIGATION</div>
            {navItems.map(item => (
              <button key={item}
                onClick={() => setActivePage(item)}
                style={{ ...S.navItem, ...(activePage === item ? S.navActive : {}) }}
              >{item}</button>
            ))}
            <div style={S.sideFooter}>
              <div style={{ fontSize:10, color:'var(--accent)', fontWeight:700, marginBottom:4 }}>🤖 Claude AI</div>
              <div style={{ fontSize:11, color:'var(--text-muted)', lineHeight:1.5 }}>
                Analyzing real MongoDB data in real time
              </div>
            </div>
          </aside>
        )}

        {/* ── MAIN ── */}
        <main style={S.main}>

          {/* Page header */}
          <div style={S.pageHead}>
            <div>
              <h1 style={S.pageTitle}>{activePage}</h1>
              <p style={{ fontSize:12, color:'var(--text-muted)', marginTop:3 }}>
                Real data from MongoDB · Claude AI powered · Welcome, {user?.name}
              </p>
            </div>
            <button style={S.refreshBtn} onClick={fetchAllData}>↻ Refresh</button>
          </div>

          {/* ── KPI CARDS ── */}
          <div style={S.kpiGrid}>
            {kpis.map(k => (
              <div key={k.label} style={S.kpiCard}>
                <div style={S.kpiTop}>
                  <span style={S.kpiLabel}>{k.label}</span>
                  <span style={{ fontSize:18 }}>{k.icon}</span>
                </div>
                <div style={{ fontSize:26, fontWeight:700, color:'var(--accent)', letterSpacing:'-0.02em' }}>{k.value}</div>
                <div style={{ display:'flex', alignItems:'center', gap:8 }}>
                  <span style={{ fontSize:11, fontWeight:700, color: k.deltaUp===true?'var(--green)':k.deltaUp===false?'var(--red)':'var(--text-muted)', background: k.deltaUp===true?'#0D2A18':k.deltaUp===false?'#2D1010':'var(--surface-alt)', borderRadius:4, padding:'2px 6px' }}>
                    {k.deltaUp===true?'▲ ':k.deltaUp===false?'▼ ':''}{k.delta}
                  </span>
                  <span style={{ fontSize:10, color:'var(--text-muted)' }}>{k.sub}</span>
                </div>
              </div>
            ))}
          </div>

          {/* ── AI PANEL ── */}
          <div style={S.aiSection}>
            <div style={{ display:'flex', gap:10, marginBottom:10 }}>
              <input
                style={S.aiInput}
                value={aiQuestion}
                onChange={e => setAiQuestion(e.target.value)}
                onKeyDown={e => e.key==='Enter' && askAI()}
                placeholder="Ask Claude AI about your real financial data..."
              />
              <button style={{ ...S.aiBtn, opacity: aiLoading?0.6:1 }} onClick={() => askAI()} disabled={aiLoading}>
                {aiLoading ? '⏳...' : '✨ Ask AI'}
              </button>
            </div>
            <div style={{ display:'flex', gap:8, flexWrap:'wrap', marginBottom:14 }}>
              {quickActions.map(a => (
                <button key={a.label} style={S.quickBtn} onClick={() => { setAiQuestion(a.q); askAI(a.q); }}>
                  {a.label}
                </button>
              ))}
            </div>
            <div style={S.aiBox}>
              <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:10 }}>
                <span style={{ fontSize:16 }}>🤖</span>
                <span style={{ fontSize:11, fontWeight:700, color:'var(--accent)', textTransform:'uppercase', letterSpacing:'0.06em' }}>Claude AI — Real Data Analysis</span>
              </div>
              {aiLoading && <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                <div style={{ width:14, height:14, border:'2px solid var(--border)', borderTopColor:'var(--accent)', borderRadius:'50%', animation:'spin 0.8s linear infinite' }} />
                <span style={{ fontSize:13, color:'var(--text-muted)' }}>Claude is reading your MongoDB data...</span>
              </div>}
              {aiResponse && !aiLoading && (
                <div className="fade-in">
                  {aiResponse.split('\n').filter(p=>p.trim()).map((p,i) => (
                    <p key={i} style={{ fontSize:13, color:'var(--text-primary)', lineHeight:1.7, marginBottom:8 }}>{p}</p>
                  ))}
                </div>
              )}
              {!aiLoading && !aiResponse && (
                <p style={{ fontSize:13, color:'var(--text-muted)' }}>
                  Ask Claude AI a question and it will analyze your real MongoDB transaction data — not fake numbers.
                </p>
              )}
            </div>
          </div>

          {/* ── CHARTS ROW ── */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14, marginBottom:16 }}>

            {/* Revenue chart */}
            <div style={S.card}>
              <div style={S.cardTitle}>Monthly Revenue</div>
              <div style={S.cardSub}>Real data from MongoDB</div>
              <ResponsiveContainer width="100%" height={200}>
                <AreaChart data={revenue}>
                  <defs>
                    <linearGradient id="rg" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="0%" stopColor="#2a78d6" stopOpacity={0.3}/>
                      <stop offset="100%" stopColor="#2a78d6" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid stroke="#1A2E4A" strokeDasharray="3 3" vertical={false}/>
                  <XAxis dataKey="month" tick={{fill:'#3A5070',fontSize:10}} axisLine={false} tickLine={false}/>
                  <YAxis tick={{fill:'#3A5070',fontSize:10}} axisLine={false} tickLine={false} tickFormatter={v=>`$${v}K`}/>
                  <Tooltip contentStyle={{background:'#111E33',border:'1px solid #1A2E4A',borderRadius:8,fontSize:12}}/>
                  <Legend wrapperStyle={{fontSize:11,color:'#6B84A8'}}/>
                  <Area type="monotone" dataKey="actual" name="Actual" stroke="#2a78d6" fill="url(#rg)" strokeWidth={2} dot={false}/>
                  <Area type="monotone" dataKey="forecast" name="AI Forecast" stroke="#1baf7a" fill="none" strokeWidth={2} dot={false} strokeDasharray="5 4"/>
                </AreaChart>
              </ResponsiveContainer>
            </div>

            {/* Segment pie */}
            <div style={S.card}>
              <div style={S.cardTitle}>Transaction Segments</div>
              <div style={S.cardSub}>Volume by type</div>
              <ResponsiveContainer width="100%" height={150}>
                <PieChart>
                  <Pie data={segmentData} dataKey="value" cx="50%" cy="50%" innerRadius={40} outerRadius={65} strokeWidth={0}>
                    {segmentData.map(s => <Cell key={s.name} fill={s.color}/>)}
                  </Pie>
                  <Tooltip contentStyle={{background:'#111E33',border:'1px solid #1A2E4A',borderRadius:8,fontSize:12}} formatter={(v,n)=>[`${v}%`,n]}/>
                </PieChart>
              </ResponsiveContainer>
              <div style={{ display:'flex', flexDirection:'column', gap:6, marginTop:6 }}>
                {segmentData.map(s => (
                  <div key={s.name} style={{ display:'flex', alignItems:'center', gap:8 }}>
                    <div style={{ width:8, height:8, borderRadius:2, background:s.color, flexShrink:0 }}/>
                    <span style={{ fontSize:12, color:'var(--text-secondary)', flex:1 }}>{s.name}</span>
                    <span style={{ fontSize:12, fontWeight:700 }}>{s.value}%</span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* ── TRANSACTIONS ── */}
          <div style={{ ...S.card, marginBottom:16 }}>
            <div style={S.cardTitle}>Recent Transactions</div>
            <div style={S.cardSub}>Real data from MongoDB — AI-flagged in red</div>
            <div style={{ display:'flex', flexDirection:'column', gap:8, marginTop:12 }}>
              {transactions.length === 0 && (
                <p style={{ color:'var(--text-muted)', fontSize:13 }}>
                  No transactions yet. Run <code style={{ color:'var(--accent)' }}>npm run seed</code> in backend to add sample data.
                </p>
              )}
              {transactions.map(t => (
                <div key={t._id} style={{ ...S.txnRow, borderLeftColor: t.isFlagged ? 'var(--red)' : 'var(--border)' }}>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:13, fontWeight:600, color:'var(--text-primary)', display:'flex', alignItems:'center', gap:8 }}>
                      {t.description}
                      {t.isFlagged && <span style={S.flagBadge}>⚠️ AI FLAGGED</span>}
                    </div>
                    <div style={{ fontSize:11, color:'var(--text-muted)', marginTop:2 }}>
                      {t.category} · {new Date(t.createdAt).toLocaleDateString()} · Risk: {t.riskScore}/100
                    </div>
                  </div>
                  <div style={{ fontSize:14, fontWeight:700, color: t.amount>=0?'var(--green)':'var(--red)', fontFamily:"'JetBrains Mono',monospace" }}>
                    {t.amount>=0?'+':''}{t.amount.toLocaleString('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0})}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* ── ANOMALY CHART ── */}
          <div style={S.card}>
            <div style={S.cardTitle}>Fraud & Anomaly Detection</div>
            <div style={S.cardSub}>Real flagged transactions vs normal per month</div>
            <ResponsiveContainer width="100%" height={160}>
              <BarChart data={anomalies}>
                <CartesianGrid stroke="#1A2E4A" strokeDasharray="3 3" vertical={false}/>
                <XAxis dataKey="month" tick={{fill:'#3A5070',fontSize:10}} axisLine={false} tickLine={false}/>
                <YAxis yAxisId="l" tick={{fill:'#3A5070',fontSize:10}} axisLine={false} tickLine={false}/>
                <YAxis yAxisId="r" orientation="right" tick={{fill:'#e34948',fontSize:10}} axisLine={false} tickLine={false}/>
                <Tooltip contentStyle={{background:'#111E33',border:'1px solid #1A2E4A',borderRadius:8,fontSize:12}}/>
                <Legend wrapperStyle={{fontSize:11,color:'#6B84A8'}}/>
                <Bar yAxisId="l" dataKey="normal"    name="Normal"    fill="#2a78d6" opacity={0.7} radius={[3,3,0,0]}/>
                <Bar yAxisId="r" dataKey="anomalies" name="Anomalies" fill="#e34948"               radius={[3,3,0,0]}/>
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* Footer */}
          <div style={{ marginTop:24, paddingTop:16, borderTop:'1px solid var(--border)', display:'flex', justifyContent:'space-between' }}>
            <span style={{ fontSize:10, color:'var(--text-muted)', fontFamily:"'JetBrains Mono',monospace" }}>
              FinSight AI · React + Node.js + MongoDB + Claude AI
            </span>
            <span style={{ fontSize:10, color:'var(--green)' }}>● All systems operational</span>
          </div>

        </main>
      </div>
    </div>
  );
}

const S = {
  topbar:    { height:56, background:'var(--surface)', borderBottom:'1px solid var(--border)', display:'flex', alignItems:'center', justifyContent:'space-between', padding:'0 20px', position:'sticky', top:0, zIndex:100 },
  topLeft:   { display:'flex', alignItems:'center', gap:10 },
  menuBtn:   { background:'none', border:'none', color:'var(--text-secondary)', cursor:'pointer', fontSize:18, padding:'4px 8px' },
  logoBox:   { fontSize:20 },
  brand:     { fontSize:15, fontWeight:700, letterSpacing:'-0.02em' },
  badge:     { fontSize:9, fontWeight:700, background:'var(--accent-dim)', color:'var(--accent)', borderRadius:4, padding:'2px 8px', letterSpacing:'0.04em' },
  topRight:  { display:'flex', alignItems:'center', gap:10 },
  userChip:  { display:'flex', alignItems:'center', gap:8, background:'var(--surface-alt)', border:'1px solid var(--border)', borderRadius:8, padding:'5px 12px' },
  avatarSmall: { width:24, height:24, borderRadius:'50%', background:'var(--accent)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:12, fontWeight:700 },
  logoutBtn: { padding:'6px 14px', background:'none', border:'1px solid var(--border)', borderRadius:6, color:'var(--text-muted)', fontSize:12, cursor:'pointer' },

  sidebar:   { width:200, background:'var(--surface)', borderRight:'1px solid var(--border)', padding:'16px 0', position:'sticky', top:56, height:'calc(100vh - 56px)', flexShrink:0 },
  sideLabel: { fontSize:9, fontWeight:700, letterSpacing:'0.1em', color:'var(--text-muted)', padding:'0 16px 12px', borderBottom:'1px solid var(--border)', marginBottom:8 },
  navItem:   { width:'100%', textAlign:'left', background:'none', border:'none', borderLeft:'2px solid transparent', padding:'10px 16px', color:'var(--text-secondary)', fontSize:13, fontWeight:500, cursor:'pointer', display:'block' },
  navActive: { background:'var(--accent-dim)', borderLeft:'2px solid var(--accent)', color:'var(--accent)' },
  sideFooter:{ margin:'auto 12px 12px', padding:12, background:'var(--surface-alt)', border:'1px solid var(--accent-dim)', borderRadius:8, marginTop:'auto' },

  main:      { flex:1, padding:24, overflowY:'auto' },
  pageHead:  { display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:20 },
  pageTitle: { fontSize:22, fontWeight:700, letterSpacing:'-0.03em' },
  refreshBtn:{ padding:'7px 14px', background:'none', border:'1px solid var(--border)', borderRadius:6, color:'var(--text-secondary)', fontSize:12, cursor:'pointer' },

  kpiGrid:   { display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:12, marginBottom:16 },
  kpiCard:   { background:'var(--surface)', border:'1px solid var(--border)', borderRadius:12, padding:'16px 18px', display:'flex', flexDirection:'column', gap:8 },
  kpiTop:    { display:'flex', justifyContent:'space-between', alignItems:'center' },
  kpiLabel:  { fontSize:10, fontWeight:700, letterSpacing:'0.08em', textTransform:'uppercase', color:'var(--text-secondary)' },

  aiSection: { marginBottom:16 },
  aiInput:   { flex:1, padding:'10px 14px', background:'var(--surface)', border:'1px solid var(--border)', borderRadius:8, color:'var(--text-primary)', fontSize:13, fontFamily:'Inter,sans-serif', outline:'none' },
  aiBtn:     { padding:'10px 18px', background:'var(--accent)', color:'#fff', border:'none', borderRadius:8, fontSize:13, fontWeight:600, cursor:'pointer', whiteSpace:'nowrap' },
  quickBtn:  { padding:'6px 12px', background:'var(--surface)', border:'1px solid var(--border)', borderRadius:6, color:'var(--text-secondary)', fontSize:11, cursor:'pointer' },
  aiBox:     { background:'var(--accent-dim)', border:'1px solid var(--accent)', borderRadius:12, padding:'16px 18px', borderLeftWidth:3 },

  card:      { background:'var(--surface)', border:'1px solid var(--border)', borderRadius:12, padding:'18px 20px' },
  cardTitle: { fontSize:14, fontWeight:700, marginBottom:3 },
  cardSub:   { fontSize:11, color:'var(--text-muted)', marginBottom:12 },

  txnRow:    { display:'flex', alignItems:'center', gap:12, padding:'10px 14px', background:'var(--surface-alt)', border:'1px solid var(--border)', borderLeft:'3px solid var(--border)', borderRadius:8 },
  flagBadge: { fontSize:9, fontWeight:700, background:'#2D1010', color:'var(--red)', borderRadius:4, padding:'2px 5px' },
};
